+        "expected no violations",
+        "empty",
+        violations
+    );
+    assert_with_log!(
+        order == vec![f3, f2, f1],
+        "finalizer LIFO order",
+        vec![f3, f2, f1],
+        order
+    );
+    test_complete!("e2e_finalizer_lifo_runs_after_cancel");
+}
