+
+impl InfiniteCounter {
+    fn new() -> Self {
+        Self { current: 0 }
+    }
+}
+
+impl Stream for InfiniteCounter {
+    type Item = i32;
+
+    fn poll_next(mut self: Pin<&mut Self>, _cx: &mut Context<'_>) -> Poll<Option<Self::Item>> {
+        let val = self.current;
+        self.current += 1;
+        Poll::Ready(Some(val))
+    }
+}
